def _(text):
    """Translate text to the current language, falling back to English."""
    if _LANG[0] == 'en':
        return text
    return _TRANSLATIONS.get(_LANG[0], {}).get(text, text)

def set_language(lang):
    _LANG[0] = lang

def _translate_all_widgets(root):
    """Walk every widget in root and translate its text/label config."""
    trans = _TRANSLATIONS.get(_LANG[0], {})
    if not trans:
        return
    for widget in root.winfo_children():
        try:
            cls = widget.winfo_class()
            if cls in ('Label', 'Button', 'Checkbutton', 'Radiobutton'):
                cur = widget.cget('text')
                if cur in trans:
                    widget.config(text=trans[cur])
            elif cls == 'TCombobox':
                pass  # combobox values handled separately
        except Exception:
            pass
        try:
            _translate_all_widgets(widget)
        except Exception:
            pass
