    def _scroll_tabs(self, delta):
        self._tab_canvas.xview_scroll(int(delta), 'units')
        self._update_tab_arrows()

    def _update_tab_arrows(self):
        try:
            x0 = self._tab_canvas.canvasx(0)
            total_w = self._tab_canvas.bbox('all')
            if not total_w:
                return
            canvas_w = self._tab_canvas.winfo_width()
            content_w = total_w[2]
            # Show/hide arrows based on scroll position
            at_left  = x0 <= 0
            at_right = (x0 + canvas_w) >= content_w - 2
            self._tab_scroll_left.config(
                fg='#555555' if at_left else '#aaaaaa')
            self._tab_scroll_right.config(
                fg='#555555' if at_right else '#aaaaaa')
        except Exception:
            pass

    def _scroll_tab_into_view(self, btn):
        """Scroll the tab bar so the active button is fully visible."""
        try:
            self._tab_canvas.update_idletasks()
            btn_x = btn.winfo_x()
            btn_w = btn.winfo_width()
            canvas_w = self._tab_canvas.winfo_width()
            scroll_x = self._tab_canvas.canvasx(0)
            # Scroll left if button is to the left of view
            if btn_x < scroll_x:
                self._tab_canvas.xview_moveto(btn_x / self._tab_canvas.bbox('all')[2])
            # Scroll right if button is to the right of view
            elif btn_x + btn_w > scroll_x + canvas_w:
                new_x = (btn_x + btn_w - canvas_w)
                total = self._tab_canvas.bbox('all')[2]
                self._tab_canvas.xview_moveto(max(0, new_x / total))
            self._update_tab_arrows()
        except Exception:
            pass

    def _switch_tab(self, key):
        self._active_tab.set(key)
        all_frames = [self._tab_build_frame, self._tab_ffpkg_frame,
                      self._tab_library_frame,
                      self._tab_images_frame, self._tab_ps5_frame,
                      self._tab_extract_frame, self._tab_files_frame,
                      self._tab_ftp_frame, self._tab_ftpbr_frame,
                      self._tab_bp_frame, self._tab_pl_frame,
                      self._tab_klog_frame, self._tab_adv_frame,
                      self._tab_cfg_frame, self._tab_help_frame]
        all_btns   = [self._tab_build_btn, self._tab_ffpkg_btn,
                      self._tab_library_btn,
                      self._tab_images_btn, self._tab_ps5_btn,
                      self._tab_extract_btn, self._tab_files_btn,
                      self._tab_ftp_btn, self._tab_ftpbr_btn,
                      self._tab_bp_btn, self._tab_pl_btn,
                      self._tab_klog_btn, self._tab_adv_btn,
                      self._tab_cfg_btn, self._tab_help_btn]
        all_keys   = ['build','ffpkg','library','images','ps5','extract','files',
                      'ftp','ftpbr','backports','payloads','klog','advanced','settings','help']
        for frame, btn, k in zip(all_frames, all_btns, all_keys):
            frame.pack_forget()
            btn.config(fg=MUTED, bg='#0a0a0a')
        idx = all_keys.index(key)
        all_frames[idx].pack(fill='both', expand=True)
        all_btns[idx].config(fg=TEXT, bg='#1a1a1a')
        self._scroll_tab_into_view(all_btns[idx])

