        fp_body = tk.Frame(fp_outer, bg=SURFACE2)
        fp_body.pack(fill='x', padx=14, pady=(8, 12))

        # Row 1: Block Size + Fragment Size
        row1 = tk.Frame(fp_body, bg=SURFACE2)
        row1.pack(fill='x', pady=(0, 8))

        tk.Label(row1, text='Block Size  (-b):', font=('Segoe UI', 9),
                 bg=SURFACE2, fg=MUTED, width=18, anchor='w').pack(side='left')
        block_opts = ['4096', '8192', '16384', '32768', '65536']
        block_disp = ['4K', '8K', '16K', '32K', '64K (default)']
        self._adv_ffpkg_block_display_var = tk.StringVar()
        def _sync_block_disp():
            v = self._adv_ffpkg_block_var.get()
            d = dict(zip(block_opts, block_disp))
            self._adv_ffpkg_block_display_var.set(d.get(v, v))
        _sync_block_disp()
        block_cb = ttk.Combobox(row1, textvariable=self._adv_ffpkg_block_display_var,
                                values=['%s  (%s)' % (v,l) for v,l in zip(block_opts,block_disp)],
                                state='readonly', font=('Segoe UI', 9), width=14)
        block_cb.pack(side='left', padx=(0, 24))
        def _on_block_pick(e):
            raw = self._adv_ffpkg_block_display_var.get().split()[0]
            self._adv_ffpkg_block_var.set(raw)
            # Clamp fragment to ≤ block
            try:
                if int(self._adv_ffpkg_frag_var.get()) > int(raw):
                    self._adv_ffpkg_frag_var.set(raw)
                    _sync_frag_disp()
            except Exception:
                pass
            self._save_adv_params()
            self._adv_refresh_summary()
        block_cb.bind('<<ComboboxSelected>>', _on_block_pick)
        # Initialise display
        _sync_block_disp()
        v0 = self._adv_ffpkg_block_var.get()
        d0 = dict(zip(block_opts, ['%s  (%s)' % (v,l) for v,l in zip(block_opts,block_disp)]))
        block_cb.set(d0.get(v0, v0))

