    def _browse_osfmount(self):
        p = filedialog.askopenfilename(
            title='Locate osfmount.com',
            filetypes=[('osfmount.com', 'osfmount.com'),
                       ('All executables', '*.com *.exe'),
                       ('All files', '*.*')])
        if p:
            p = p.replace('/', '\\')
            self._osfmount_path_var.set(p)
            self._settings['osfmount_path'] = p
            save_settings(self._settings)
            self._refresh_osf_status()

    def _detect_osfmount(self):
        found = self._find_osfmount()
        if found:
            self._osfmount_path_var.set(found)
            self._settings['osfmount_path'] = found
            save_settings(self._settings)
            self._refresh_osf_status()
        else:
            self._osf_found_var.set('\u2717 Not found — use Browse to locate it manually')

    def _refresh_osf_status(self):
        found = self._find_osfmount()
        if found:
            self._osf_found_var.set('\u2713 Found: ' + found)
            if hasattr(self, '_osf_found_var'):
                try:
                    # Hide the banner if it was shown
                    for w in self.winfo_children():
                        if isinstance(w, tk.Frame) and w.cget('bg') == '#3a1500':
                            w.pack_forget()
                except Exception:
                    pass
        else:
            self._osf_found_var.set('\u2717 Not detected — click Browse to locate osfmount.com')

    def _open_tutorial_guide(self):
        """Open the tutorial HTML guide — looks next to the exe, then online."""
        import webbrowser

        # Check next to the exe first
        exe_dir = os.path.dirname(sys.executable if getattr(sys, 'frozen', False)
                                  else os.path.abspath(__file__))
        candidates = [
            os.path.join(exe_dir, 'tutorial.html'),
            os.path.join(exe_dir, 'tutorial', 'tutorial.html'),
            os.path.join(os.path.dirname(exe_dir), 'tutorial.html'),
        ]
        for path in candidates:
            if os.path.isfile(path):
                webbrowser.open('file:///' + path.replace('\\', '/'))
                return

        # Not found locally — open GitHub releases page
        if messagebox.askyesno('Tutorial guide not found',
                'tutorial.html was not found next to the exe.\n\n'
                'Download it from the GitHub releases page?\n'
                '(It\'s included in the release zip)'):
            webbrowser.open(
                'https://github.com/kerrdec97/ps5-exfat-builder/releases')

    def _build_help_tab(self, parent):
        """Help tab — shows the full tutorial HTML in an embedded viewer.
        Tries to load the latest version from GitHub; falls back to bundled."""

        # ── Header ──
        hdr = tk.Frame(parent, bg=BG)
        hdr.pack(fill='x', padx=24, pady=(12, 4))
        tk.Label(hdr, text='Help & Tutorial',
                 font=('Segoe UI', 13, 'bold'), bg=BG, fg=TEXT).pack(side='left')
        self._help_status_var = tk.StringVar(value='')
        tk.Label(hdr, textvariable=self._help_status_var,
                 font=('Segoe UI', 8), bg=BG, fg=MUTED).pack(side='right')

        # ── Toolbar ──
        toolbar = tk.Frame(parent, bg=BG)
        toolbar.pack(fill='x', padx=24, pady=(0, 6))
        tk.Button(toolbar, text='\U0001f4c4 Open in browser',
                  font=('Segoe UI', 9), bg=SURFACE2, fg=TEXT,
                  activebackground=BORDER, activeforeground=TEXT,
                  relief='flat', bd=0, padx=10, pady=4, cursor='hand2',
                  command=self._help_open_browser).pack(side='left')
        tk.Button(toolbar, text='\U0001f504 Check for updated tutorial',
                  font=('Segoe UI', 9), bg=SURFACE2, fg=MUTED,
                  activebackground=BORDER, activeforeground=TEXT,
                  relief='flat', bd=0, padx=10, pady=4, cursor='hand2',
                  command=self._help_fetch_latest).pack(side='left', padx=(6,0))

        # ── Embedded HTML viewer (tkinterweb if available, else text fallback) ──
        viewer_frame = tk.Frame(parent, bg='#111',
                                highlightbackground=BORDER, highlightthickness=1)
        viewer_frame.pack(fill='both', expand=True, padx=24, pady=(0,8))

        self._help_html_data  = [None]  # cached HTML bytes
        self._help_viewer     = [None]  # tkinterweb widget if available

        try:
            import tkinterweb
            hv = tkinterweb.HtmlFrame(viewer_frame, messages_enabled=False)
            hv.pack(fill='both', expand=True)
            self._help_viewer[0] = hv
        except ImportError:
            # Fallback: scrollable text with key FAQ content
            self._help_text_fallback(viewer_frame)

        # Load bundled tutorial immediately, then try to fetch latest
        self.after(100, self._help_load_bundled)
        self.after(2000, self._help_fetch_latest)

    def _help_text_fallback(self, parent):
        """Simple text fallback when tkinterweb isn't installed."""
