    def _help_load_bundled(self):
        """Load the bundled tutorial HTML (base64 embedded in the exe)."""
        try:
            import base64 as _b64
            html_bytes = _b64.b64decode(_TUTORIAL_HTML_B64)
            self._help_html_data[0] = html_bytes
            self._help_render(html_bytes)
            self._help_status_var.set('Showing bundled tutorial v' + APP_VERSION)
        except Exception as e:
            self._help_status_var.set('Could not load tutorial: ' + str(e))

    def _help_fetch_latest(self):
        """Try to fetch the latest tutorial from GitHub raw content."""
        self._help_status_var.set('Checking for updated tutorial...')
        url = ('https://raw.githubusercontent.com/'
               'kerrdec97/ps5-exfat-builder/main/tutorial.html')
        def worker():
            try:
                import urllib.request
                req = urllib.request.Request(url,
                    headers={'User-Agent': 'ps5-exfat-builder/' + APP_VERSION})
                with urllib.request.urlopen(req, timeout=8) as r:
                    html_bytes = r.read()
                # Only update if it's actually HTML
                if b'<!DOCTYPE' in html_bytes[:20] or b'<html' in html_bytes[:20]:
                    self._help_html_data[0] = html_bytes
                    self.after(0, self._help_render, html_bytes)
                    self.after(0, self._help_status_var.set,
                               'Tutorial loaded from GitHub \u2713')
                else:
                    self.after(0, self._help_status_var.set,
                               'Showing bundled tutorial (GitHub version not available)')
            except Exception:
                self.after(0, self._help_status_var.set,
                           'Showing bundled tutorial (offline)')
        threading.Thread(target=worker, daemon=True).start()

    def _help_render(self, html_bytes):
        """Render HTML in the viewer if tkinterweb is available."""
        hv = self._help_viewer[0]
        if hv is None:
            return  # text fallback already shown
        try:
            html_str = html_bytes.decode('utf-8', errors='replace')
            hv.load_html(html_str)
        except Exception:
            pass

    def _help_open_browser(self):
        """Save tutorial to temp file and open in default browser."""
        import webbrowser, tempfile as _tf
        html_bytes = self._help_html_data[0]
        if not html_bytes:
            # Try bundled
            try:
                import base64 as _b64
                html_bytes = _b64.b64decode(_TUTORIAL_HTML_B64)
            except Exception:
                messagebox.showwarning('Tutorial not available',
                    'Could not load the tutorial file.')
                return
        try:
            tmp = _tf.NamedTemporaryFile(
                suffix='.html', prefix='exfat_tutorial_',
                delete=False, mode='wb')
            tmp.write(html_bytes)
            tmp.close()
            webbrowser.open('file:///' + tmp.name.replace('\\', '/'))
        except Exception as e:
            messagebox.showerror('Error', str(e))
        # Scrollable canvas
        outer = tk.Frame(parent, bg=BG)
        outer.pack(fill='both', expand=True)
        canvas = tk.Canvas(outer, bg=BG, highlightthickness=0)
        sb = tk.Scrollbar(outer, command=canvas.yview,
                          bg=SURFACE2, troughcolor=BG)
        canvas.configure(yscrollcommand=sb.set)
        sb.pack(side='right', fill='y')
        canvas.pack(side='left', fill='both', expand=True)
        body = tk.Frame(canvas, bg=BG)
        canvas.create_window((0,0), window=body, anchor='nw', tags='hb')
        body.bind('<Configure>', lambda e:
            canvas.configure(scrollregion=canvas.bbox('all')))
