    # ── ffpkg helpers ─────────────────────────────────────────────────────────
    def _field_ffpkg(self, parent, label, var, browse_cmd):
        row = tk.Frame(parent, bg=BG)
        row.pack(fill='x', pady=(0, 6))
        tk.Label(row, text=label, font=('Segoe UI', 9),
                 bg=BG, fg=MUTED, anchor='w').pack(fill='x')
        inner = tk.Frame(row, bg=BG)
        inner.pack(fill='x', pady=(3, 0))
        ef = tk.Frame(inner, bg=FIELD_BG,
                      highlightbackground=BORDER, highlightthickness=1)
        ef.pack(side='left', fill='x', expand=True)
        tk.Entry(ef, textvariable=var, font=('Consolas', 10),
                 bg=FIELD_BG, fg=FIELD_FG, insertbackground=FIELD_FG,
                 selectbackground=FIELD_SEL_BG, selectforeground=FIELD_SEL_FG,
                 relief='flat', bd=6, state='readonly').pack(fill='x')
        tk.Button(inner, text='Browse', font=('Segoe UI', 9),
                  bg=SURFACE2, fg=TEXT, activebackground=BORDER,
                  activeforeground=TEXT, relief='flat', bd=0,
                  padx=14, pady=6, cursor='hand2',
                  command=browse_cmd).pack(side='left', padx=(6, 0))
        return row

    def _ffpkg_browse_game(self):
        p = filedialog.askdirectory(
            title='Select game root folder (containing eboot.bin)')
        if not p:
            return
        p = p.replace('/', '\\')
        self._ffpkg_game_folder.set(p)
        self._ffpkg_detect_game_async(p)

    def _ffpkg_browse_output(self):
        p = filedialog.askdirectory(title='Select output directory')
        if not p:
            return
        p = p.replace('/', '\\')
        self._ffpkg_output_dir.set(p)
        self._settings['ffpkg_output_dir'] = p
        save_settings(self._settings)

    def _ffpkg_detect_game_async(self, folder):
        self._ffpkg_info_title_var.set('Reading game info...')
        self._ffpkg_info_frame.pack(fill='x', pady=(0, 8))
        threading.Thread(
            target=lambda: self._ffpkg_detect_game(folder),
            daemon=True).start()

    def _ffpkg_detect_game(self, folder):
        folder = os.path.normpath(folder)
        title, title_id, version = get_game_info(folder)
        if not title_id:
            m = re.search(r'((?:PPSA|CUSA|PPLH)\d{5})',
                          os.path.basename(folder), re.IGNORECASE)
            if m:
                title_id = m.group(1).upper()

        # Cover art
        cover_path = self._load_cover_art(folder)
        if cover_path:
            try:
                from PIL import Image, ImageTk
                img = Image.open(cover_path).resize((56, 56), Image.LANCZOS)
                self._ffpkg_cover_image = ImageTk.PhotoImage(img)
                self._ffpkg_cover_label.config(
                    image=self._ffpkg_cover_image, text='', width=56, height=56)
            except Exception:
                self._ffpkg_cover_label.config(
                    image='', text='\U0001f3ae', font=('Segoe UI', 20), fg=INFO_FG)
        else:
            self._ffpkg_cover_label.config(
                image='', text='\U0001f3ae', font=('Segoe UI', 20), fg='#333333')

        # Size + file count — calculate and cache for ETA/progress use during build
        def calc_size():
            size_bytes = self._get_folder_size(folder)
            file_count = sum(len(files) for _, _, files in os.walk(folder))
            norm = os.path.normpath(folder)
            self._ffpkg_folder_sizes[norm] = size_bytes
            self._ffpkg_folder_file_counts[norm] = file_count
            size_str = ('%.2f GB' % (size_bytes/1024**3)
                        if size_bytes >= 1024**3
                        else '%.0f MB' % (size_bytes/1024**2))
            self.after(0, self._ffpkg_info_size_var.set,
                       '\U0001f4be ' + size_str + ' estimated image size')
        threading.Thread(target=calc_size, daemon=True).start()

        display = title or title_id or os.path.basename(folder)
        self.after(0, self._ffpkg_info_title_var.set, display)
        self.after(0, lambda: self._ffpkg_info_frame.pack(
            fill='x', pady=(0, 6),
            before=self._ffpkg_output_dir_frame))

        # Auto filename: TITLEID (version).ffpkg  or  Title (version).ffpkg
        name = build_exfat_name(title, title_id, version)
        name = name.replace('.exfat', '.ffpkg')
        self.after(0, self._ffpkg_output_name.set, name)
        self.after(0, self._ffpkg_auto_label.pack, )
        self.after(0, self._ffpkg_filename_preview.config,
                   {'fg': '#ffffff'})

    def _ffpkg_add_to_queue(self):
        game  = self._ffpkg_game_folder.get().strip()
        odir  = self._ffpkg_output_dir.get().strip()
        name  = self._ffpkg_output_name.get().strip() or 'game.ffpkg'
        if not name.lower().endswith('.ffpkg'):
            name += '.ffpkg'
        if not game:
            messagebox.showwarning('Missing', 'Please select a game folder.')
            return
        if not odir:
            messagebox.showwarning('Missing', 'Please select an output directory.')
            return
        # Duplicate check
        for existing in self._ffpkg_queue:
            if os.path.normpath(existing['folder']) == os.path.normpath(game):
                if not messagebox.askyesno('Duplicate',
                        'This folder is already in the queue. Add again?'):
                    return
                break
        self._ffpkg_queue.append({
            'folder': game,
            'odir':   odir,
            'name':   name,
            'status': 'waiting',
        })
        self._ffpkg_render_queue()

    def _ffpkg_clear_queue(self):
        if self._ffpkg_building:
            messagebox.showwarning('Building', 'Cannot clear queue while building.')
            return
        self._ffpkg_queue.clear()
        self._ffpkg_render_queue()

    def _ffpkg_render_queue(self):
        for w in self._ffpkg_queue_frame.winfo_children():
            w.destroy()
        if not self._ffpkg_queue:
            tk.Label(self._ffpkg_queue_frame,
                     text='Queue is empty — add a game folder above',
                     font=('Segoe UI', 9), bg=SURFACE2, fg='#333333',
                     pady=14).pack()
            return
        for i, item in enumerate(self._ffpkg_queue):
            bg = QUEUE_ODD if i % 2 == 0 else QUEUE_EVEN
            row = tk.Frame(self._ffpkg_queue_frame, bg=bg)
            row.pack(fill='x')
            # Status dot
            dot = tk.Canvas(row, width=12, height=12, bg=bg, highlightthickness=0)
            dot.pack(side='left', padx=(10, 6), pady=8)
            colour = {
                'waiting':  BORDER,
                'building': ACCENT,
                'done':     SUCCESS,
                'failed':   DANGER,
            }.get(item['status'], BORDER)
            dot.create_oval(1, 1, 11, 11, fill=colour, outline='')
            # Name
            tk.Label(row, text=item['name'],
                     font=('Segoe UI', 9), bg=bg, fg=TEXT,
                     anchor='w').pack(side='left', fill='x', expand=True, padx=(0, 8))
            # Remove button (only when not building)
            if not self._ffpkg_building:
                idx = i
                tk.Button(row, text='\u2715',
                          font=('Segoe UI', 8), bg=bg, fg=DANGER,
                          activebackground=bg, activeforeground=DANGER,
                          relief='flat', bd=0, padx=8, cursor='hand2',
                          command=lambda ix=idx: self._ffpkg_remove_item(ix)
                          ).pack(side='right', padx=(0, 6))
            # Upload button if done
            if item['status'] == 'done':
                out_path = os.path.join(item['odir'], item['name'])
                tk.Button(row, text='\u2191 PS5',
                          font=('Segoe UI', 8), bg=SURFACE2, fg=ACCENT,
                          activebackground=BORDER, activeforeground=ACCENT,
                          relief='flat', bd=0, padx=8, pady=2, cursor='hand2',
                          command=lambda p=out_path: self._ftp_upload_file(p)
                          ).pack(side='right', padx=(0, 4))

    def _ffpkg_remove_item(self, idx):
        if 0 <= idx < len(self._ffpkg_queue):
            self._ffpkg_queue.pop(idx)
            self._ffpkg_render_queue()

    def _ffpkg_run_queue(self):
        if self._ffpkg_building:
            return
        waiting = [i for i, it in enumerate(self._ffpkg_queue)
                   if it['status'] == 'waiting']
        if not waiting:
            messagebox.showwarning('Nothing to build',
                'No waiting items in the ffpkg queue.')
            return
        # Ensure UFS2Tool is extracted
        if not self._ffpkg_ufs2_exe or not os.path.isfile(self._ffpkg_ufs2_exe):
            try:
                temp_dir = self._settings.get('temp_dir') or None
                self._ffpkg_ufs2_exe = extract_ufs2tool(temp_dir)
            except Exception as e:
                messagebox.showerror('UFS2Tool extraction failed', str(e))
                return
        self._ffpkg_building = True
        self._ffpkg_build_btn.config(state='disabled', text='Building...')
        self._ffpkg_render_queue()
        self._ffpkg_process_next(waiting, 0)

    def _ffpkg_process_next(self, indices, pos):
        if pos >= len(indices):
            self._ffpkg_building = False
            self._ffpkg_build_btn.config(state='normal', text='Build All')
            self._ffpkg_set_progress(100, 'All done!', '')
            self._set_status('ffpkg: %d image(s) built \u2713' % len(indices), SUCCESS)
            messagebox.showinfo('ffpkg Complete',
                '%d ffpkg image(s) built successfully!' % len(indices))
            self._ffpkg_render_queue()
            return
        idx  = indices[pos]
        item = self._ffpkg_queue[idx]
        item['status'] = 'building'
        self._ffpkg_render_queue()

        out_path    = os.path.join(item['odir'], item['name'])
        game_folder = item['folder']
        exe         = self._ffpkg_ufs2_exe

        # Build command — use advanced parameters from the Advanced tab
        block  = self._adv_ffpkg_block_var.get()  or '65536'
        frag   = self._adv_ffpkg_frag_var.get()   or '65536'
        minfr  = self._adv_ffpkg_minfree_var.get() or '0'
        inode  = self._adv_ffpkg_inode_var.get()  or '262144'
        try:
            if int(frag) > int(block):
                frag = block
        except Exception:
            frag = block
        cmd = [exe, 'newfs',
               '-O', '2',
               '-b', block,
               '-f', frag,
               '-m', minfr,
               '-S', '512',
               '-i', inode,
               '-D', game_folder,
               out_path]

        label = 'Building %d/%d: %s' % (pos + 1, len(indices), item['name'])
        self._ffpkg_set_progress(0, label, '')
        self._ffpkg_start_time   = time.time()
        self._ffpkg_stage        = 'init'
        self._ffpkg_total_files  = 0
        self._ffpkg_out_path     = out_path
        self._ffpkg_expected_size       = 0
        self._ffpkg_current_queue_idx   = idx
        # Load size from cache immediately — may have been pre-calculated on folder select
        try:
            _norm = os.path.normpath(item['folder'])
            _cached = self._ffpkg_folder_sizes.get(_norm, 0)
            if _cached > 0:
                self._ffpkg_expected_size = _cached
            _fc = self._ffpkg_folder_file_counts.get(_norm, 0)
            if _fc > 0:
                self._ffpkg_total_files = _fc
        except Exception:
            pass
        self._ffpkg_poll_drive_free_start = None
        self._ffpkg_copy_start_t = None
        self._ffpkg_copy_start_size = 0
        self._ffpkg_final_size   = 0
        self._ffpkg_poll_id      = None
        self._set_status(label, ACCENT)
        self._ffpkg_log_clear()
        self._ffpkg_log('[ffpkg] ' + ' '.join(
            ('"' + a + '"' if ' ' in a else a) for a in cmd) + '\n\n')
        os.makedirs(item['odir'], exist_ok=True)

        # Pre-count source files for progress context
        def count_files():
            try:
                n = sum(len(files) for _, _, files in os.walk(game_folder))
                self._ffpkg_total_files = n
            except Exception:
                pass
        threading.Thread(target=count_files, daemon=True).start()

        def worker():
            try:
                proc = subprocess.Popen(
                    cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                    text=True, encoding='utf-8', errors='replace',
                    cwd=os.path.dirname(exe),
                    creationflags=subprocess.CREATE_NO_WINDOW)
                for line in proc.stdout:
                    self.after(0, self._ffpkg_handle_line, line, pos, len(indices))
                proc.wait()
                self.after(0, self._ffpkg_stop_poll)
                self.after(0, self._ffpkg_item_done,
                           proc.returncode, idx, indices, pos, out_path)
            except Exception as ex:
                self.after(0, self._ffpkg_stop_poll)
                self.after(0, self._ffpkg_item_error, str(ex), idx, indices, pos)

        threading.Thread(target=worker, daemon=True).start()

    # Stages mapped to bar ranges:
    #   0–30%  : init / writing cylinder groups  (UFS2Tool reports 0–100% here)
    #   30–95% : adding files to image           (UFS2Tool reports 0–100% here)
    #   95–100%: finalising / done

    def _ffpkg_handle_line(self, line, pos, total):
        self._ffpkg_log(line)
        elapsed = time.time() - self._ffpkg_start_time if self._ffpkg_start_time else 0
        el_str  = 'Elapsed: %dm %02ds' % (int(elapsed//60), int(elapsed%60))
        stripped = line.strip()

        # ── Stage detection ──────────────────────────────────────────────────
        if 'Writing cylinder groups' in stripped:
            self._ffpkg_stage = 'cylgroups'
            self._ffpkg_activate_dot(0)

        elif 'Adding files to image' in stripped:
            self._ffpkg_stage = 'copying'
            self._ffpkg_activate_dot(1)
            self._ffpkg_copy_start_t = time.time()
            self._ffpkg_start_poll()   # starts expected_size background calc

        elif 'Populated image with' in stripped:
            self._ffpkg_stage = 'done'
            self._ffpkg_activate_dot(2)
            self._ffpkg_stop_poll()
            m2 = re.search(r'(\d+)\s+files?', stripped)
            files_done = int(m2.group(1)) if m2 else self._ffpkg_total_files
            total_files = self._ffpkg_total_files or files_done
            self._ffpkg_set_progress(
                97,
                'Finalising... (%d/%d files)' % (files_done, total_files),
                el_str)
            return

        elif 'Image created successfully' in stripped:
            self._ffpkg_stage = 'done'
            self._ffpkg_stop_poll()
            return

        # ── Percentage parsing ───────────────────────────────────────────────
        m = re.search(r'(\d{1,3})\s*%', stripped)
        if not m:
            return
        raw_pct = min(int(m.group(1)), 100)

        if self._ffpkg_stage == 'cylgroups':
            mapped = int(raw_pct * 0.30)
            self._ffpkg_set_progress(
                mapped,
                '[1/2] Writing filesystem structure... %d%%' % raw_pct,
                el_str)

        elif self._ffpkg_stage == 'copying':
            mapped = 30 + int(raw_pct * 0.65)

            # Parse UFS2Tool's rich output line:
            # "Adding files to image... 34% (83/148 files, 6.20 GiB/18.23 GiB)"
            files_done = files_total = 0
            written_gib = total_gib = 0.0

            mf = re.search(r'\((\d+)/(\d+)\s+files?', stripped)
            if mf:
                files_done  = int(mf.group(1))
                files_total = int(mf.group(2))
                if files_total > 0:
                    self._ffpkg_total_files = files_total

            mg = re.search(r'([\d.]+)\s*GiB\s*/\s*([\d.]+)\s*GiB', stripped)
            if mg:
                written_gib = float(mg.group(1))
                total_gib   = float(mg.group(2))

            # Step label
            if files_done > 0 and files_total > 0:
                label = '[2/2] Copying files... %d/%d  (%d%%)' % (
                    files_done, files_total, raw_pct)
            else:
                label = '[2/2] Copying files... %d%%' % raw_pct

            # ETA line — built from parsed values
            copy_elapsed = (time.time() - self._ffpkg_copy_start_t
                            if self._ffpkg_copy_start_t else elapsed)
            eta_parts = ['Elapsed: %dm %02ds' % (int(elapsed//60), int(elapsed%60))]

            if written_gib > 0:
                eta_parts.append('%.2f GB written' % written_gib)
            if total_gib > 0 and written_gib > 0:
                rem = total_gib - written_gib
                if rem > 0:
                    eta_parts.append('%.2f GB remaining' % rem)

            if written_gib > 0 and copy_elapsed > 1:
                speed_mbs = (written_gib * 1024) / copy_elapsed
                eta_parts.append('%.1f MB/s' % speed_mbs)
                if total_gib > 0 and rem > 0 and speed_mbs > 0:
                    eta_s = (rem * 1024) / speed_mbs
                    if eta_s < 5:
                        eta_parts.append('Almost done')
                    elif eta_s < 60:
                        eta_parts.append('ETA: %ds' % int(eta_s))
                    else:
                        eta_parts.append('ETA: %dm %02ds' % (
                            int(eta_s // 60), int(eta_s % 60)))

            self._ffpkg_set_progress(mapped, label, '  \u2022  '.join(eta_parts))

    def _ffpkg_start_poll(self):
        """Set expected size and file count from cache, or recalculate in background."""
        try:
            folder = self._ffpkg_queue[self._ffpkg_current_queue_idx]['folder']
            norm   = os.path.normpath(folder)
            cached_size  = self._ffpkg_folder_sizes.get(norm, 0)
            cached_count = self._ffpkg_folder_file_counts.get(norm, 0)
            if cached_size > 0:
                self._ffpkg_expected_size = cached_size
            if cached_count > 0:
                self._ffpkg_total_files = cached_count
            if cached_size == 0 or cached_count == 0:
                # Calculate anything not yet cached
                def _calc():
                    try:
                        if cached_size == 0:
                            sz = self._get_folder_size(folder)
                            self._ffpkg_expected_size = sz
                            self._ffpkg_folder_sizes[norm] = sz
                        if cached_count == 0:
                            n = sum(len(files) for _, _, files in os.walk(folder))
                            self._ffpkg_total_files = n
                            self._ffpkg_folder_file_counts[norm] = n
                    except Exception:
                        pass
                threading.Thread(target=_calc, daemon=True).start()
        except Exception:
            pass

    def _ffpkg_stop_poll(self):
        if self._ffpkg_poll_id is not None:
            try:
                self.after_cancel(self._ffpkg_poll_id)
            except Exception:
                pass
            self._ffpkg_poll_id = None

    def _ffpkg_activate_dot(self, index):
        if not hasattr(self, '_ffpkg_stage_dots'):
            return
        for i, (dot, lbl) in enumerate(self._ffpkg_stage_dots):
            if i < index:
                dot.itemconfig('dot', fill=SUCCESS)
                lbl.config(fg=SUCCESS)
            elif i == index:
                dot.itemconfig('dot', fill=ACCENT)
                lbl.config(fg=ACCENT)
            else:
                dot.itemconfig('dot', fill=BORDER)
                lbl.config(fg=MUTED)

    def _ffpkg_item_done(self, returncode, idx, indices, pos, out_path):
        elapsed = time.time() - self._ffpkg_start_time if self._ffpkg_start_time else 0
        m, s = int(elapsed//60), int(elapsed%60)
        if returncode == 0:
            self._ffpkg_queue[idx]['status'] = 'done'
            self._ffpkg_activate_dot(len(self._ffpkg_stage_dots) if hasattr(self, '_ffpkg_stage_dots') else 3)
            self._ffpkg_set_progress(100, 'Complete!',
                'Finished in %dm %02ds' % (m, s))
            self._ffpkg_log('\n[OK] Done: ' + out_path + '\n')
            self._set_status('ffpkg built: ' + os.path.basename(out_path), SUCCESS)
            # Auto-upload if enabled
            if self._ftp_auto_var.get() and self._ftp_ip_var.get().strip():
                if messagebox.askyesno('FTP Upload',
                        'ffpkg built!\n\nUpload to PS5 now?\n' + out_path):
                    self._ftp_upload_file(out_path,
                        on_done=lambda: self._ffpkg_process_next(indices, pos+1))
                    self._ffpkg_render_queue()
                    return
            self._ffpkg_render_queue()
            self._ffpkg_process_next(indices, pos + 1)
        else:
            self._ffpkg_queue[idx]['status'] = 'failed'
            self._ffpkg_set_progress(self._ffpkg_current_pct, 'Failed', '')
            self._set_status('ffpkg build failed (exit %d)' % returncode, DANGER)
            self._ffpkg_log('\n[ERROR] Exit code: %d\n' % returncode)
            self._ffpkg_render_queue()
            if messagebox.askyesno('Build failed',
                    'ffpkg build failed for:\n' + out_path +
                    '\n\nContinue with remaining items?'):
                self._ffpkg_process_next(indices, pos + 1)
            else:
                self._ffpkg_building = False
                self._ffpkg_build_btn.config(state='normal', text='Build All')

    def _ffpkg_item_error(self, msg, idx, indices, pos):
        self._ffpkg_queue[idx]['status'] = 'failed'
        self._set_status('ffpkg error: ' + msg, DANGER)
        self._ffpkg_log('\n[ERROR] ' + msg + '\n')
        self._ffpkg_render_queue()
        if messagebox.askyesno('Error', 'UFS2Tool error:\n' + msg +
                '\n\nContinue with remaining items?'):
            self._ffpkg_process_next(indices, pos + 1)
        else:
            self._ffpkg_building = False
            self._ffpkg_build_btn.config(state='normal', text='Build All')

    def _ffpkg_set_progress(self, pct, step_text=None, eta_text=None):
        self._ffpkg_current_pct = pct
        self._ffpkg_update_bar(pct)
        self._ffpkg_pct_var.set(str(int(pct)) + '%')
        if step_text is not None:
            self._ffpkg_step_var.set(step_text)
        if eta_text is not None:
            self._ffpkg_eta_var.set(eta_text)

    def _ffpkg_update_bar(self, pct):
        try:
            w = self._ffpkg_bar_canvas.winfo_width()
            fill_w = int(w * pct / 100)
            self._ffpkg_bar_canvas.coords(self._ffpkg_bar_rect, 0, 0, fill_w, 20)
            self._ffpkg_bar_canvas.itemconfig(
                self._ffpkg_bar_rect, fill=SUCCESS if pct >= 100 else ACCENT)
        except Exception:
            pass

    def _ffpkg_toggle_log(self, force_open=False):
        if force_open and self._ffpkg_log_visible.get():
            return
        if force_open:
            self._ffpkg_log_visible.set(True)
        else:
            self._ffpkg_log_visible.set(not self._ffpkg_log_visible.get())
        if self._ffpkg_log_visible.get():
            self._ffpkg_log_body.pack(fill='x', padx=24, pady=(2, 6))
            self._ffpkg_log_toggle.config(
                text='\u25bc  OUTPUT LOG', fg=TEXT)
        else:
            self._ffpkg_log_body.pack_forget()
            self._ffpkg_log_toggle.config(
                text='\u25b6  OUTPUT LOG', fg=MUTED)

    def _ffpkg_log(self, text):
        self._ffpkg_toggle_log(force_open=True)
        self._ffpkg_log_box.config(state='normal')
        self._ffpkg_log_box.insert('end', text)
        self._ffpkg_log_box.see('end')
        self._ffpkg_log_box.config(state='disabled')

    def _ffpkg_log_clear(self):
        self._ffpkg_log_box.config(state='normal')
        self._ffpkg_log_box.delete('1.0', 'end')
        self._ffpkg_log_box.config(state='disabled')

    def _ffpkg_check_dotnet(self):
        """Check if .NET 8 runtime is available."""
        def worker():
            try:
                result = subprocess.run(
                    ['dotnet', '--list-runtimes'],
                    capture_output=True, text=True, timeout=10)
                output = result.stdout + result.stderr
                if 'Microsoft.NETCore.App 8.' in output:
                    self.after(0, messagebox.showinfo, _('.NET 8 Found'),
                        _('.NET 8 runtime is installed ✓\n\nUFS2Tool should work correctly.'))
                else:
                    self.after(0, messagebox.showwarning, _('.NET 8 Not Found'),
                        _('.NET 8 runtime is required for UFS2Tool.\n\nDownload from: https://dotnet.microsoft.com/download/dotnet/8.0\n\nInstall the ".NET Runtime 8.x" (not SDK).'))
            except FileNotFoundError:
                self.after(0, messagebox.showwarning, _('.NET 8 Not Found'),
                    _('.NET is not installed or not in PATH.\n\nUFS2Tool requires .NET 8 Runtime.\n\nDownload from: https://dotnet.microsoft.com/download/dotnet/8.0\n\nInstall the ".NET Runtime 8.x" (not SDK).'))
            except Exception as e:
                self.after(0, messagebox.showerror, 'Check failed', str(e))
        threading.Thread(target=worker, daemon=True).start()

    def _rebuild_all_tabs(self):
        """Destroy and rebuild every tab frame with the current language."""
        # Save active tab so we can restore it
        active = self._active_tab.get()

        # Stop any ffpkg poll safely
        self._ffpkg_stop_poll()

        # Map of frame → builder method
        rebuilds = [
            (self._tab_build_frame,   self._build_build_tab),
            (self._tab_ffpkg_frame,   self._build_ffpkg_tab),
            (self._tab_library_frame, self._build_library_tab),
            (self._tab_images_frame,  self._build_images_tab),
            (self._tab_ps5_frame,     self._build_ps5_tab),
            (self._tab_extract_frame, self._build_extract_tab),
            (self._tab_files_frame,   self._build_files_tab),
            (self._tab_ftp_frame,     self._build_ftp_tab),
            (self._tab_ftpbr_frame,   self._build_ftpbr_tab),
            (self._tab_bp_frame,      self._build_backports_tab),
            (self._tab_pl_frame,      self._build_payload_tab),
            (self._tab_klog_frame,    self._build_klog_tab),
            (self._tab_adv_frame,     self._build_advanced_tab),
            (self._tab_cfg_frame,     self._build_settings_tab),
            (self._tab_help_frame,    self._build_help_tab),
        ]

        for frame, builder in rebuilds:
            # Destroy all children
            for w in frame.winfo_children():
                w.destroy()
            try:
                builder(frame)
            except Exception as ex:
                import traceback
                traceback.print_exc()

        # Translate tab bar buttons
        tab_keys = [
            (self._tab_build_btn,   'exFAT'),
            (self._tab_ffpkg_btn,   'ffpkg'),
            (self._tab_library_btn, 'Library'),
            (self._tab_images_btn,  'My Images'),
            (self._tab_ps5_btn,     'PS5 Manager'),
            (self._tab_extract_btn, 'Extract'),
            (self._tab_files_btn,   'File Manager'),
            (self._tab_ftp_btn,     'FTP Upload'),
            (self._tab_ftpbr_btn,   'PS5 Browser'),
            (self._tab_bp_btn,      'Backports'),
            (self._tab_pl_btn,      'Payloads'),
            (self._tab_klog_btn,    'Klog'),
            (self._tab_adv_btn,     'Advanced'),
            (self._tab_cfg_btn,     'Settings'),
            (self._tab_help_btn,    'Help'),
        ]
        icons = ['\U0001f528', '\U0001f4e6', '\U0001f4da', '\U0001f4be',
                 '\U0001f3ae', '\U0001f4e4', '\U0001f5c2', '\U0001f4e1',
                 '\U0001f4e1', '\U0001f9e9', '\U0001f4e6', '\U0001f4cb',
                 '\u2699\ufe0f', '\u2699', '\u2753']
        for (btn, key), icon in zip(tab_keys, icons):
            try:
                label = _('%s' % key)
                btn.config(text='%s  %s' % (icon, label))
            except Exception:
                pass

        # After rebuilding, walk all widgets and translate any remaining English strings
        if _LANG[0] != 'en':
            _translate_all_widgets(self)

        # Restore active tab display
        self._switch_tab(active)

    def _build_build_tab(self, parent):
        # ── No settings strip here — use the Settings tab ──

        tk.Frame(parent, bg=BORDER, height=1).pack(fill='x', pady=(6, 0))

        # ── Add to queue form ──
